package com.v2ray.ang.handlerimport android.content.Contextimport android.util.Logimport com.google.gson.Gsonimport com.v2ray.ang.AppConfigimport com.v2ray.ang.BuildConfigimport com.v2ray.ang.dto.CheckUpdateResultimport com.v2ray.ang.dto.VersionInfoimport com.v2ray.ang.util.HttpUtilimport java.util.Localeobject UpdateCheckHandler {    private const val TAG = "UpdateCheckHandler"    private const val TIMEOUT = 15000     fun checkForUpdate(context: Context): CheckUpdateResult {        return try {            val updateUrl = getUpdateUrl(context)            Log.d(TAG, "Checking for update from: $updateUrl")            val responseJson = HttpUtil.getUrlContent(updateUrl, TIMEOUT)            if (responseJson.isNullOrEmpty()) {                Log.e(TAG, "Empty response from update server")                return CheckUpdateResult(                    hasUpdate = false,                    error = "无法获取版本信息"                )            }            val versionInfo = Gson().fromJson(responseJson, VersionInfo::class.java)            val currentVersionCode = BuildConfig.VERSION_CODE            val currentVersionName = BuildConfig.VERSION_NAME            Log.d(TAG, "Current version: $currentVersionName ($currentVersionCode)")            Log.d(TAG, "Remote version: ${versionInfo.versionName} (${versionInfo.versionCode})")            val hasUpdate = versionInfo.versionCode > currentVersionCode            val isForceUpdate = currentVersionCode < versionInfo.minVersionCode            if (hasUpdate) {                Log.d(TAG, "Update available! Force update: $isForceUpdate")            } else {                Log.d(TAG, "Already at latest version")            }            CheckUpdateResult(                hasUpdate = hasUpdate,                latestVersion = versionInfo.versionName,                releaseNotes = versionInfo.releaseNotes,                downloadUrl = versionInfo.downloadUrl,                error = null,                isPreRelease = false             )        } catch (e: Exception) {            Log.e(TAG, "Error checking for update", e)            CheckUpdateResult(                hasUpdate = false,                error = e.message ?: "检查更新失败"            )        }    }    private fun getUpdateUrl(context: Context): String {        val currentLocale = context.resources.configuration.locales[0]        val language = currentLocale.language        return if (language == Locale.CHINESE.language) {            AppConfig.APP_UPDATE_CHECK_URL_CN        } else {            AppConfig.APP_UPDATE_CHECK_URL_EN        }    }    fun checkForForceUpdate(context: Context): Pair<Boolean, VersionInfo?> {        return try {            val updateUrl = getUpdateUrl(context)            val responseJson = HttpUtil.getUrlContent(updateUrl, TIMEOUT)            if (responseJson.isNullOrEmpty()) {                return Pair(false, null)            }            val versionInfo = Gson().fromJson(responseJson, VersionInfo::class.java)            val currentVersionCode = BuildConfig.VERSION_CODE            val needsForceUpdate = currentVersionCode < versionInfo.minVersionCode            if (needsForceUpdate) {                Log.w(TAG, "Force update required! Current: $currentVersionCode, Min: ${versionInfo.minVersionCode}")            }            Pair(needsForceUpdate, versionInfo)        } catch (e: Exception) {            Log.e(TAG, "Error checking for force update", e)            Pair(false, null)        }    }}